window.__QUIZ_DATA__=[{"id":"objective>Physics>2003>1","subject":"Physics","year":"2003","type":"Objective","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"A tuber of cassava can be processed into powder. This explains the fact that","images":[],"options":{"A":"matter can change spontaneously from one state to another","B":"matter cannot be destroyed","C":"force is required to change matter from one state to another","D":"matter is made up of tiny particles"},"answer":"D","explanation":"The process of grinding the cassava into powder involves breaking down the larger particles of the cassava into smaller particles, which demonstrates that matter is made up of tiny particles.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2003>2","subject":"Physics","year":"2003","type":"Objective","topic":"FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES\u2019 PRINCIPLE","question":"A piece of metal of relative density 5.0 weighs 60N in air. Calculate its weight when fully immersed in water.","images":[],"options":{"A":"4N","B":"5N","C":"48N","D":"60N"},"answer":"C","explanation":"R.D = 5  W1 = Weight in air = 60N  W2 = Weight in water = ?  R.D=W1W1 - W2=51  =6060 - W2=51  1 \u00d7 60 = 5(60 - W2)  60 = 300 - 5W2  W2=2405=48N","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>3","subject":"Physics","year":"2003","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A net force of 15 N acts upon a body of mass 3kg for 5s. Calculate the change in the speed of the body.","images":[],"options":{"A":"25.0ms-1","B":"9.0ms-1","C":"2.5ms-1","D":"1.0ms-1"},"answer":"A","explanation":"Ft = M(v - u)  Ft = Mdv (where v - u = dv)  dv=FtM  dv=15 \u00d7 53  \u21d2 25.0ms-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>4","subject":"Physics","year":"2003","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : FIRST LAW","question":"The tendency of a body to remain at rest when a force is applied to it is called","images":[],"options":{"A":"impulse","B":"momentum","C":"inertia","D":"friction"},"answer":"C","explanation":"The tendency of a body to remain at rest when a force is applied to it is called inertia. Inertia is a property of matter by which it continues in its existing state of rest or uniform motion in a straight line, unless that state is changed by an external force.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2003>5","subject":"Physics","year":"2003","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A force acts on a body for 0.5s changing its momentum from 16.0kgms-1 to 21.0kgms-1. Calculate the magnitude of the force.","images":[],"options":{"A":"42.0N","B":"37.0N","C":"32.0N","D":"10.0N"},"answer":"D","explanation":"The force can be calculated using the formula for impulse, which is the change in momentum. The formula is F = \u0394p/\u0394t, where F is the force, \u0394p is the change in momentum and \u0394t is the change in time. Substituting the given values gives F = (21.0kgms-1 - 16.0kgms-1) / 0.5s = 10N.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>6","subject":"Physics","year":"2003","type":"Objective","topic":"RECTILINEAR ACCELERATION : UNIFORM/NON-UNIFORM ACCELERATION","question":"Which of the graphs below shows the motion of a body with uniform retardation?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"D","explanation":"The velocity keeps reducing with time in retardation.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2003>7","subject":"Physics","year":"2003","type":"Objective","topic":"RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION","question":"A moving object is said to have uniform acceleration if its","images":[],"options":{"A":"displacement decreases at a constant rate","B":"speed is directly proportional to time","C":"velocity increases by equal amount in equal time intervals","D":"velocity varies inversely with time"},"answer":"C","explanation":"Uniform acceleration is defined as the rate at which an object changes its velocity. This means that the velocity of the object increases or decreases by an equal amount in equal intervals of time. Therefore, the correct answer is 'velocity increases by equal amount in equal time intervals'.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>8","subject":"Physics","year":"2003","type":"Objective","topic":"SIMPLE HARMONIC MOTION : PERIOD, FREQUENCY AND AMPLITUDE OF A BODY EXECUTING S.H.M","question":"The period of an oscillatory motion is defined as the","images":[],"options":{"A":"average of the times used in completing different numbers of oscillations","B":"time to complete a number of oscillations","C":"time to complete one oscillation","D":"time taken to move from one extreme position to the other"},"answer":"C","explanation":"The period of an oscillatory motion is the time taken for one complete cycle of vibration to pass a given point. As such, the period of an oscillation is defined as the time to complete one oscillation.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>9","subject":"Physics","year":"2003","type":"Objective","topic":"WORK, ENERGY AND POWER : CONSERVATION OF MECHANICAL ENERGY","question":"The mass on a loaded spiral spring oscillates vertically between two extreme positions P and R equidistant from the equilibrium position Q. Which of the following statements about the system is not correct?","images":[],"options":{"A":"The momentum of the mass is maximum at Q","B":"The elastic potential energy of the spring is maximum at Q","C":"The kinetic energy of the mass is maximum at P","D":"The total energy of the system is always constant"},"answer":"B","explanation":"In a simple harmonic motion like a mass on a spring, the elastic potential energy is maximum at the extreme positions (P and R), not at the equilibrium position (Q). Therefore, the statement 'The elastic potential energy of the spring is maximum at Q' is not correct.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2003>10","subject":"Physics","year":"2003","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A ball of mass 5.0kg hits a smooth vertical wall normally with a speed of 2 ms-1. Determine the magnitude of the resulting impulse.","images":[],"options":{"A":"20.0 kgms-1","B":"10.0 kgms-1","C":"5.0 kgms-1","D":"2.5 kgms-1"},"answer":"B","explanation":"m = 5kg, v = 2ms-1  Ft = M(V2 - V1) = MV  \u21d2 5 \u00d7 2 = 10kgms-1","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>11","subject":"Physics","year":"2003","type":"Objective","topic":"MACHINES :","question":"Which of the following statements correctly defines a simple machine? A device","images":[],"options":{"A":"that can provide electric current","B":"which can only carry people from one place to another","C":"with which work can be done easily","D":"which changes the state of rest or of uniform motion of an object along a straight line"},"answer":"C","explanation":"A simple machine is a mechanical device that changes the direction or magnitude of a force. In general, they can be defined as the simplest mechanisms that use mechanical advantage (also called leverage) to multiply force. A simple machine uses a single applied force to do work against a single load force. It makes work easier, hence option 3 is correct.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2003>12","subject":"Physics","year":"2003","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"A platinum resistance thermometer has a resistance of 4\u03a9 at 0\u00b0C and 10\u03a9 at 100\u00b0C. Assuming the resistance changes uniformly with temperature, calculate the resistance of the thermometer when the temperature is 45\u00b0C.","images":[],"options":{"A":"14.0\u03a9","B":"6.7\u03a9","C":"3.2\u03a9","D":"2.7\u03a9"},"answer":"B","explanation":"\u03b8\u00b0=R\u03b8 - R0R100 - R0\u00d7100  =R\u03b8 - 410 - 4\u00d7100  45=R\u03b8 - 46\u00d7100  270 = 100R\u03b8 - 400  270 + 400 = 100R\u03b8  R\u03b8=670100   \u21d2 6.7\u03a9","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>13","subject":"Physics","year":"2003","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"A metal rod of length 100cm is heated through 100\u00b0C, calculate the change in length of the rod. [linear expansivity of the material of the rod is 3 \u00d7 10-5K-1]","images":[],"options":{"A":"4mm","B":"3mm","C":"2mm","D":"1mm"},"answer":"B","explanation":"\u03b1=\u0394LLo(\u0394\u03b8)  substituting  3\u00d710-5=\u0394L100 \u00d7 100cm  \u0394L = 3 \u00d7 10-5 \u00d7 100 \u00d7 100  \u21d2 0.3cm = 3mm","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>14","subject":"Physics","year":"2003","type":"Objective","topic":"HEAT ENERGY : HEAT CAPACITY","question":"The heat capacity of a calorimeter is the amount of energy required to","images":[],"options":{"A":"change the temperature of 1kg of the calorimeter by 1k","B":"change 1kg mass of the calorimeter to liquid at the same temperature","C":"change the temperature of the calorimeter by 1K","D":"melt the calorimeter into liquid at a constant temperature"},"answer":"C","explanation":"The heat capacity of an object is defined as the amount of heat energy required to raise the temperature of the object by one degree Kelvin (or Celsius, as the size of the degree is the same in both scales). Therefore, the heat capacity of a calorimeter is the amount of energy required to change the temperature of the calorimeter by 1K, which corresponds to option 3.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2003>15","subject":"Physics","year":"2003","type":"Objective","topic":"HEAT ENERGY : SPECIFIC LATENT HEAT OF VAPORISATION","question":"Which of the following statements about latent heat of vaporisation is correct. It","images":[],"options":{"A":"weakens the adhesive forces between molecules of a liquid and those of its container","B":"breaks completely the force of attraction between the molecules of a liquid","C":"adds to the heat content of a liquid","D":"increases the cohesive forces between liquid molecules"},"answer":"B","explanation":"breaks completely the force of attraction between the molecules of a liquid","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>16","subject":"Physics","year":"2003","type":"Objective","topic":"HEAT ENERGY : GAS LAWS","question":"When the pressure of a fixed mass of gas is doubled at constant temperature, the volume of the gas is","images":[],"options":{"A":"increased four times","B":"doubled","C":"unchanged","D":"halved"},"answer":"D","explanation":"According to Boyle's law, the pressure of a gas is inversely proportional to its volume at constant temperature. This means that if the pressure is doubled, the volume is halved.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>17","subject":"Physics","year":"2003","type":"Objective","topic":"HEAT ENERGY : GAS LAWS","question":"The volume of a given mass of an ideal gas at 327K and 9.52 \u00d7 104Pa is 40cm3. Calculate the volume of the gas at 273K and 1.034 \u00d7 105 Pa.","images":[],"options":{"A":"68.23 cm3","B":"47.91 cm3","C":"44.60 cm3","D":"30.75 cm3"},"answer":"D","explanation":"T1 = 373K; P1 = 9.52 \u00d7 104Pa  V1 = 40cm3  T2 = 273K, P2 = 1.034 \u00d7 105Pa, V2 = ?  P1V1T1=P2V2T2  V2=P1V1T2T1P2=9.52 \u00d7 104 \u00d7 40 \u00d7 2733.27 \u00d7 1.034 \u00d7 105  V2 = 30.75cm3","marks":"1","difficulty":"3"},{"id":"objective>Physics>2003>18","subject":"Physics","year":"2003","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"The diagram above represents the displacement D versus time, t, graph of a progressive wave. Deduce the frequency of the wave.","images":["data:image/png;base64,"],"options":{"A":"20 Hz","B":"10 Hz","C":"5 Hz","D":"4 Hz"},"answer":"B","explanation":"t = 0.10second from graph  F=1T=10.10=10Hz","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>19","subject":"Physics","year":"2003","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"A wave of wavelength 0.30m travels 900m in 3.0s, calculate its frequency.","images":[],"options":{"A":"68.0 Hz","B":"225.0 Hz","C":"270.0 Hz","D":"1000.0 Hz"},"answer":"D","explanation":"Velocity=DT=9003=300m/s  Velocity = F\u03bb   Therefore, 300m/s = 0.3mk  F=3000.3=1000Hz","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>20","subject":"Physics","year":"2003","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"Which of the following conditions is necessary for the occurrence of total internal reflection of light?","images":[],"options":{"A":"Light must travel from an optically less dense to a denser medium","B":"The angle of incidence must be equal to the critical angle","C":"The angle of incidence must be greater than the critical angle","D":"The angle of refraction must be 90\u00b0"},"answer":"C","explanation":"Total internal reflection occurs when light travels from a denser medium to a less dense medium and the angle of incidence is greater than the critical angle. The critical angle is the angle of incidence that provides an angle of refraction of 90 degrees. If the angle of incidence is greater than this, no refraction occurs and all the light is reflected back into the denser medium.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2003>21","subject":"Physics","year":"2003","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"The image which cannot be formed on a screen is said to be","images":[],"options":{"A":"inverted","B":"erect","C":"real","D":"virtual"},"answer":"D","explanation":"A real image is formed when light rays converge at a point and can be projected on a screen. A virtual image, on the other hand, is formed when light rays diverge and appear to be coming from a point but cannot be projected on a screen. Therefore, the image which cannot be formed on a screen is said to be virtual.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2003>22","subject":"Physics","year":"2003","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"An object is placed in the principal axis and at the centre of curvature of a concave mirror, the image of the object formed by the mirror is","images":[],"options":{"A":"real and magnified","B":"real and inverted","C":"erect and magnified","D":"erect and virtual"},"answer":"B","explanation":"When an object is placed at the centre of curvature of a concave mirror, the image formed is real, inverted and of the same size as the object. This is because the rays of light parallel to the principal axis and those passing through the centre of curvature are reflected back along the same path and intersect at the centre of curvature.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>23","subject":"Physics","year":"2003","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"A converging lens produces an image four times as large as an object placed 25cm from the lens. Calculate its focal length.","images":[],"options":{"A":"100cm","B":"33cm","C":"29cm","D":"20cm"},"answer":"D","explanation":"M = 4  M=VU  4=V25  V = 100cm  1F=1U+1V=125+1100  4+1100=5100=120  F = 20cm","marks":"1","difficulty":"3"},{"id":"objective>Physics>2003>24","subject":"Physics","year":"2003","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"The horizontal floor of a water reservoir appears to be 1.0m deep when viewed vertically from above. If the refractive index of water is 1.35, calculate the real depth of the reservoir.","images":[],"options":{"A":"2.35m","B":"1.35m","C":"1.00m","D":"0.35m"},"answer":"B","explanation":"n=real depthapparent depth  Apparent depth = 1.0m, n = 1.35, real depth = ?  1.35=real depth1  real depth = 1 \u00d7 1.35 = 1.35m","marks":"1","difficulty":"3"},{"id":"objective>Physics>2003>25","subject":"Physics","year":"2003","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"A converging lens has a focal length of 5cm. Determine its power.","images":[],"options":{"A":"+20.0D","B":"+0.2D","C":"-20.0D","D":"-0.2D"},"answer":"A","explanation":"The power of a lens is the reciprocal of its focal length in meters. In this case, the focal length is 5cm, or 0.05m. Therefore, the power is 1/0.05 = 20D. The power of a converging lens is positive, so the correct answer is +20.0D, which corresponds to option 1.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>26","subject":"Physics","year":"2003","type":"Objective","topic":"LIGHT WAVES : DISPERSION OF WHITE LIGHT","question":"Which of the following pairs of light rays shows the widest separation in the spectrum of white light?","images":[],"options":{"A":"Green and blue","B":"Orange and indigo","C":"Blue and violet","D":"Red and yellow"},"answer":"B","explanation":"It is observed that there is a wide distance between orange and indigo","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>27","subject":"Physics","year":"2003","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"Which of the following statements about the human eye and the camera is correct?","images":[],"options":{"A":"Both form virtual images of objects","B":"The image formed by the eye is upright in the retina while that formed by the camera is inverted on the film","C":"The inside of both of them is blackened to absorb unwanted light","D":"The focal length of both the eye lens and the camera lens can be varied"},"answer":"C","explanation":"The interior of both the  human and camera is black and light proof so as to prevent the reflction of stray rays of light","marks":"1","difficulty":"3"},{"id":"objective>Physics>2003>28","subject":"Physics","year":"2003","type":"Objective","topic":"SOUND WAVES : SPEED OF SOUND","question":"The speed of sound in air is directly proportional to","images":[],"options":{"A":"its temperature on the celsius scale","B":"its temperature on the thermodynamic scale","C":"the cube root of its temperature on the celsius scale","D":"the square root of its temperature on the absolute scale"},"answer":"D","explanation":"Speed of sound waves directly with square root of temperature in kelvin.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2003>29","subject":"Physics","year":"2003","type":"Objective","topic":"SOUND WAVES : CHARACTERISTICS OF SOUND","question":"Which of the following statements about the characteristics of sound waves is correct?","images":[],"options":{"A":"Loudness decreases with increase in intensity","B":"The pitch of a note is determined by its amplitude","C":"The intensity of a sound wave is proportional to its amplitude","D":"The quality of a note depends on its overtones"},"answer":"D","explanation":"The quality of a note depends on its overtones. Overtones are the frequencies higher than the fundamental frequency that are present in a sound. They give a sound its unique quality, or timbre, which allows us to distinguish between different musical instruments or voices. The other options are incorrect. Loudness is directly proportional to the intensity of a sound, not inversely. The pitch of a note is determined by its frequency, not its amplitude. The intensity of a sound wave is proportional to the square of its amplitude, not directly to its amplitude.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>30","subject":"Physics","year":"2003","type":"Objective","topic":"SOUND WAVES : SPEED OF SOUND","question":"A sonometer wire of linear density 0.08 kg m-1 subjected to a tension of 800N is plucked. Calculate the speed of a pulse which moves from one end of the wire to the other.","images":[],"options":{"A":"179.0 ms-1","B":"100.0 ms-1","C":"15.8 ms-1","D":"8.0 ms-1"},"answer":"B","explanation":"The speed of a pulse in a sonometer wire can be calculated using the formula v = &radic;T/\u03bc&nbsp;, where T is the tension in the wire and \u03bc is the linear density of the wire. Substituting the given values, we get v = &radic;800/0.08&nbsp; = 100 ms-1.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2003>31","subject":"Physics","year":"2003","type":"Objective","topic":"SOUND WAVES : SOURCES OF SOUND","question":"Which of the following instruments gives a pure note when sounded?","images":[],"options":{"A":"Talking drum","B":"Siren","C":"Tuning fork","D":"Guitar"},"answer":"C","explanation":"A tuning fork produces a pure note when sounded. This is because it vibrates at a single frequency, producing a sound wave with a single frequency. This results in a pure tone.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2003>32","subject":"Physics","year":"2003","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC LINES OF FORCE","question":"Which of the following features of an electrostatic line of force is not correct?","images":[],"options":{"A":"It is an imaginary line which a positive charge would describe if it is free to move","B":"The tangent drawn at any point on a curved line of force shows the direction of the electric field intensity at that point","C":"It is sometimes curved","D":"It can cross another line of force in a region of intense electric field"},"answer":"D","explanation":"Electrostatic lines of force cannot cross each other. This is because the direction of the electric field is given by the tangent to the line of force at that point. If two lines of force cross each other, there would be two tangents at the point of intersection, which would mean that the electric field has two directions at that point. This is not possible.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>33","subject":"Physics","year":"2003","type":"Objective","topic":"DESCRIPTION PROPERTY OF FIELDS : CONCEPT OF FIELDS","question":"Which of the following statements about a force field is correct?","images":[],"options":{"A":"Electrostatic, gravitational and magnetic forces are always attractive.","B":"Electric, gravitational and magnetic fields obey inverse square laws","C":"Field lines are real but their corresponding fields are imaginary","D":"Field lines and their corresponding fields are both real"},"answer":"B","explanation":"The correct statement is that electric, gravitational and magnetic fields obey inverse square laws. This is because the strength of these fields decreases with the square of the distance from the source. This is known as the inverse square law. The other options are incorrect. Electrostatic, gravitational and magnetic forces are not always attractive. For example, like charges repel each other in an electrostatic field. Field lines are not real, they are a visual representation used to describe the direction and strength of a field. The field itself is a region where a force would be felt.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>34","subject":"Physics","year":"2003","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"A positively charged glass rod is placed near the cap of a positively charged electroscope. The divergence of the leaf is observed to","images":[],"options":{"A":"decrease","B":"increase","C":"remain the same","D":"increase and collapse immediately"},"answer":"B","explanation":"The repulsion force from like charges increases divergence.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>35","subject":"Physics","year":"2003","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"Two identical cells each of emf 2V and internal resistance 1.0\u03a9 are connected in parallel. The combination is connected to an external load of 1.5\u03a9. Calculate the current in the circuit.","images":[],"options":{"A":"0.57A","B":"1.00A","C":"1.14A","D":"2.00A"},"answer":"B","explanation":"Connectedinparallel,effectiveresistance=1r+r=11+1=12  effective emf = 2v  external resistance = 1.5  I=VR=20.5+1.5=22=1A","marks":"1","difficulty":"3"},{"id":"objective>Physics>2003>36","subject":"Physics","year":"2003","type":"Objective","topic":"ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY","question":"Which of the following factors does not affect the electric resistance of a wire?","images":[],"options":{"A":"Length","B":"Mass","C":"Temperature","D":"Cross sectional area"},"answer":"B","explanation":"The electric resistance of a wire is affected by its length, temperature, and cross-sectional area, but not its mass. The resistance of a wire increases with its length and temperature and decreases with its cross-sectional area. This is because resistance is a measure of how much a material opposes the flow of electric current, and these factors affect how easily current can flow. However, the mass of the wire does not directly affect its resistance.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2003>37","subject":"Physics","year":"2003","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"A current of 10A passes through a conductor for 10s, calculate the charge flowing through the conductor","images":[],"options":{"A":"100.0C","B":"10.0C","C":"1.0C","D":"0.1C"},"answer":"A","explanation":"The charge flowing through a conductor can be calculated using the formula Q = It, where Q is the charge, I is the current, and t is the time. In this case, I = 10A and t = 10s, so Q = 10A * 10s = 100C. Therefore, the charge flowing through the conductor is 100C.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2003>38","subject":"Physics","year":"2003","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC ENERGY AND POWER","question":"A lamp is rated 240V 60W, calculate the resistance of its filament.","images":[],"options":{"A":"240\u03a9","B":"360\u03a9","C":"960\u03a9","D":"1440\u03a9"},"answer":"C","explanation":"The resistance of a lamp's filament can be calculated using Ohm's law, which states that the resistance (R) is equal to the voltage (V) divided by the current (I). The current can be calculated by dividing the power (P) by the voltage, so I = P/V = 60W/240V = 0.25A. Therefore, R = V/I = 240V/0.25A = 960\u03a9.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>39","subject":"Physics","year":"2003","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC ENERGY AND POWER","question":"The maximum power dissipated by a 100\u03a9 resistor in a circuit is 4W, calculate the voltage across the resistor.","images":[],"options":{"A":"10V","B":"20V","C":"25V","D":"400V"},"answer":"B","explanation":"The power dissipated by a resistor is given by the formula P = V^2/R, where P is the power, V is the voltage, and R is the resistance. Rearranging the formula to find V gives V = &radic;P*R&nbsp;. Substituting the given values gives V = &radic;4W * 100\u03a9&nbsp; = 20V. Therefore, the correct answer is 20V.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>40","subject":"Physics","year":"2003","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE","question":"One difference between a reactance and a resistance in an alternating current circuit is","images":[],"options":{"A":"resistance is larger than reactance","B":"energy is not dissipated in a reactance","C":"energy is stored in a resistance but not in a reactance","D":"the current in a reactance is lower than in the resistance"},"answer":"B","explanation":"The main difference between reactance and resistance in an alternating current circuit is that energy is not dissipated in a reactance. In a resistance, the electrical energy is converted into heat and is dissipated, whereas in a reactance, the energy is stored in the electric or magnetic field and is returned to the circuit when the conditions change.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>41","subject":"Physics","year":"2003","type":"Objective","topic":"ELECTRIC FIELD : CONCEPTS OF ELECTRIC FIELD, ELECTRIC FIELD INTENSITY (POTENTIAL GRADIENT) AND ELECTRIC POTENTIAL.","question":"The diagram above shows the resultant electric field pattern due to two electric point charges P and S. Which of the following statements is correct","images":["data:image/png;base64,"],"options":{"A":"P is negatively charged while S is positively charged","B":"P is positively charged while S is negatively charged","C":"Both P and S are positively charged","D":"Both P and S are negatively charged"},"answer":"D","explanation":"Both P and S are negatively charged since their arrows point inward.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2003>42","subject":"Physics","year":"2003","type":"Objective","topic":"MAGNETIC FIELD : MAGNETIZATION AND DEMAGNETIZATION","question":"The bar magnet illustrated in the diagram above picks up an unmagnetised steel nail X. In turn, X picks up a similar nail Y and so on. The nails are said to be magnetised by","images":["data:image/png;base64,"],"options":{"A":"conduction","B":"single touch","C":"induction","D":"divided touch"},"answer":"C","explanation":"The process by which the unmagnetized steel nails become magnetized when they come into contact with the bar magnet and each other is known as induction.    In this case, the bar magnet induces magnetism in the nearby unmagnetized steel nails without direct contact through a flow of electric current, which is characteristic of magnetic induction.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>43","subject":"Physics","year":"2003","type":"Objective","topic":"ELECTROMAGNETIC FIELD : FARADAY\u2019S LAW","question":"The direction of induced current in a straight wire placed in a magnetic field is determined by using","images":[],"options":{"A":"Fleming's right hand rule","B":"Maxwell's screw rule","C":"Faraday's law","D":"Lenz's law"},"answer":"A","explanation":"Fleming's right hand helps tell direction of induced current.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2003>44","subject":"Physics","year":"2003","type":"Objective","topic":"MAGNETIC FIELD : USE OF ELECTROMAGNETS","question":"Which of the following statements about an electromagnet is not correct?","images":[],"options":{"A":"It is a temporary magnet","B":"Its strength depends on the current","C":"Its strength depends on the number of units in its coil","D":"It has permanent poles"},"answer":"D","explanation":"An electromagnet is a type of magnet in which the magnetic field is produced by an electric current. The magnetic field disappears when the current is turned off. Therefore, it does not have permanent poles. The strength of the magnetic field produced by such a magnet can be changed by changing the amount of electric current that passes through it, which means its strength depends on the current. The number of turns in the coil also affects the strength of the electromagnet. Hence, the statement 'It has permanent poles' is not correct.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2003>45","subject":"Physics","year":"2003","type":"Objective","topic":"ELECTROMAGNETIC WAVES: : ELECTROMAGNETIC SPECTRUM","question":"Which of the following statements is true of ultra violet radiations. It","images":[],"options":{"A":"supports the sensation of hearing","B":"does not cause the emission of electrons from metals","C":"is an electromagnetic wave","D":"is not capable of causing sun burn"},"answer":"C","explanation":"Ultraviolet (UV) radiation is a form of electromagnetic radiation that comes from the sun and man-made sources like tanning beds. UV radiation is a component of the electromagnetic spectrum with wavelengths shorter than visible light but longer than X-rays. It does not support the sensation of hearing, it can cause the emission of electrons from metals (photoelectric effect), and it is capable of causing sunburn. Hence, the statement 'It is an electromagnetic wave' is true.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>46","subject":"Physics","year":"2003","type":"Objective","topic":"STRUCTURE OF THE ATOM : MODELS OF THE ATOM","question":"Which of the following statements is not true of the isotopes of an element? They","images":[],"options":{"A":"are atoms of the same element","B":"have the same chemical properties","C":"have the same atomic number","D":"have the same mass number"},"answer":"D","explanation":"Isotopes are variants of a particular chemical element which differ in neutron number, and consequently in nucleon number. All isotopes of a given element have the same number of protons but different numbers of neutrons in each atom. They are atoms of the same element, have the same chemical properties, and have the same atomic number. However, they do not have the same mass number because the mass number is the total number of protons and neutrons in an atom, and this can vary between isotopes. Hence, the statement 'They have the same mass number' is not true.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>47","subject":"Physics","year":"2003","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"A radioactive element has a decay constant of 0.077s-1, calculate its half life.","images":[],"options":{"A":"12.5s","B":"9.0s","C":"5.1s","D":"0.5s"},"answer":"B","explanation":"\u03bb = 0.077s-1  WhereT=0.692\u03bb  =0.6920.077=9.0s","marks":"1","difficulty":"3"},{"id":"objective>Physics>2003>48","subject":"Physics","year":"2003","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"The minimum energy required to remove an electron from an atom is known as","images":[],"options":{"A":"excitation energy","B":"ionization energy","C":"binding energy","D":"photon energy"},"answer":"B","explanation":"The minimum energy required to remove an electron from an atom is known as the ionization energy. Ionization energy is the energy required to remove an electron from a gaseous atom or ion. The term is often used to describe the first ionization energy, which is the energy required to remove the outermost, or highest energy, electron from a neutral atom.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2003>49","subject":"Physics","year":"2003","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"Nuclear fission is preferred to nuclear fusion in the generation of energy because","images":[],"options":{"A":"very high temperatures are required for fusion","B":"the raw materials for fusion are not easily obtained","C":"energy obtained from fusion is relatively smaller","D":"the by product of fusion are very dangerous"},"answer":"A","explanation":"Nuclear fission is preferred to nuclear fusion in the generation of energy because very high temperatures are required for fusion. Nuclear fusion requires temperatures of millions of degrees to overcome the electrostatic repulsion between the positively charged nuclei. On the other hand, nuclear fission can occur at much lower temperatures, making it more feasible for energy generation.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2003>50","subject":"Physics","year":"2003","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"Which of the following reactions represents nuclear fusion?","images":[],"options":{"A":"21H + 21H \u2192 31He + 10n","B":"23592u + 10n \u2192 14556Ba + 9036Kr + 2 10n","C":"23490Th \u2192 0-1n + 23491Pa","D":"23892U \u2192 42He + 23490Th"},"answer":"A","explanation":"Nuclear fusion is a reaction in which two or more atomic nuclei are combined to form one or more different atomic nuclei and subatomic particles (neutrons or protons). The difference in mass between the reactants and products is manifested as the release of large amounts of energy. The option 1 represents this process, where two hydrogen nuclei (protons) are combined to form a helium nucleus and a neutron.","marks":"1","difficulty":"3"}];